package com.chaobo.scm.supplier.domain.profile;public enum SupplierAdmissionStatus{POTENTIAL(1,"潜在"),PENDING(2,"待审核"),APPROVED(3,"已通过"),REJECTED(4,"已驳回"),WITHDRAWN(5,"已撤回");private final int code;private final String label;SupplierAdmissionStatus(int code,String label){this.code=code;this.label=label;}public int code(){return code;}public String label(){return label;}public static SupplierAdmissionStatus fromCode(int code){for(var v:values())if(v.code==code)return v;throw new IllegalArgumentException("未知准入状态");}}
